#include<bits/stdc++.h>
using namespace std;
char a[2000005];
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0);
	cout.tie(0);
	int n, t, j = 0;
	cin >> a >> t;
	while(t){
		int x = a[j] - '0', s = j;
		for(int i = j; i <= t + j; i++){
			if(a[i] == '\0')return 0;
			int y = a[i] - '0';
			if(x > y)x = y, s = i;
		}
		t -= s - j;
		j = s + 1;
		if(x)cout << x;
		else if(a[j] == '\0')cout << 0;
	}
	for(int i = j; a[i] != '\0'; i++)cout << a[i];
}
